<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>Snake</title>
  <style>
    :root {
      color-scheme: dark;
      --bg: #10141c;
      --panel: #19212d;
      --line: #2b394a;
      --text: #eaf3ff;
      --muted: #a9bdd3;
      --green: #57e389;
      --green-dark: #24935a;
      --food: #ff5c7c;
      --accent: #6ea8fe;
    }

    * { box-sizing: border-box; }

    body {
      margin: 0;
      min-height: 100vh;
      display: grid;
      place-items: center;
      background:
        radial-gradient(circle at 50% 15%, #26354a 0, transparent 38rem),
        var(--bg);
      color: var(--text);
      font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
    }

    .game-shell {
      width: min(94vw, 680px);
      text-align: center;
      padding: 28px 16px 34px;
    }

    h1 {
      margin: 0 0 8px;
      font-size: 2rem;
      letter-spacing: 0.12em;
      text-transform: uppercase;
    }

    #score {
      color: var(--muted);
      font-size: 1.05rem;
      font-weight: 700;
      margin-bottom: 18px;
    }

    .board-frame {
      width: 600px;
      max-width: none;
      margin: 0 auto;
      padding: 14px;
      background: linear-gradient(145deg, #243246, #121923);
      border: 1px solid #3a4c63;
      border-radius: 18px;
      box-shadow: 0 18px 55px rgba(0, 0, 0, 0.4);
    }

    #snake {
      display: block;
      width: 560px;
      height: 560px;
      margin: auto;
      background: #0c121a;
      border-radius: 9px;
      image-rendering: pixelated;
    }

    .controls {
      display: flex;
      justify-content: center;
      flex-wrap: wrap;
      gap: 10px;
      margin-top: 20px;
    }

    button {
      appearance: none;
      border: 1px solid #41556e;
      border-radius: 9px;
      padding: 10px 18px;
      color: var(--text);
      background: #223044;
      cursor: pointer;
      font: inherit;
      font-weight: 750;
      transition: transform 0.12s, background 0.12s, border-color 0.12s;
    }

    button:hover {
      background: #30445f;
      border-color: var(--accent);
    }

    button:active {
      transform: translateY(1px);
    }

    #start {
      background: #1d6b43;
      border-color: #43c97b;
    }

    #start:hover {
      background: #258454;
    }

    .hint {
      margin: 17px 0 0;
      color: var(--muted);
      font-size: 0.92rem;
    }

    kbd {
      padding: 2px 6px;
      border: 1px solid #50647d;
      border-bottom-width: 2px;
      border-radius: 5px;
      background: #1f2a39;
      font-family: inherit;
      font-size: 0.85em;
    }
  </style>
</head>
<body>
  <main class="game-shell">
    <h1>Snake</h1>
    <div id="score">Score: 0</div>

    <div class="board-frame">
      <canvas id="snake" width="600" height="600" aria-label="Snake game board"></canvas>
    </div>

    <div class="controls">
      <button id="start" type="button">Start</button>
      <button id="pause" type="button">Pause</button>
      <button id="reset" type="button">Reset</button>
    </div>

    <p class="hint">Steer with the <kbd>←</kbd> <kbd>↑</kbd> <kbd>↓</kbd> <kbd>→</kbd> arrow keys</p>
  </main>

  <script>
    (() => {
      const canvas = document.getElementById("snake");
      const ctx = canvas.getContext("2d");
      const scoreEl = document.getElementById("score");
      const startButton = document.getElementById("start");
      const pauseButton = document.getElementById("pause");
      const resetButton = document.getElementById("reset");

      const w = 20;
      const h = 20;
      const cell = canvas.width / w;
      const tickMs = 125;

      let body = [];
      let direction = "right";
      let queuedDirection = null;
      let foodCell = [14, 10];
      let points = 0;
      let isAlive = true;
      let timer = null;

      const vectors = {
        up: [0, -1],
        down: [0, 1],
        left: [-1, 0],
        right: [1, 0]
      };

      const opposite = {
        up: "down",
        down: "up",
        left: "right",
        right: "left"
      };

      function updateScore() {
        scoreEl.textContent = "Score: " + points;
      }

      function sameCell(a, b) {
        return a[0] === b[0] && a[1] === b[1];
      }

      function cellOccupied(x, y) {
        return body.some(part => part[0] === x && part[1] === y);
      }

      function placeRandomFood() {
        const free = [];
        for (let y = 0; y < h; y++) {
          for (let x = 0; x < w; x++) {
            if (!cellOccupied(x, y)) free.push([x, y]);
          }
        }
        foodCell = free.length ? free[Math.floor(Math.random() * free.length)] : null;
      }

      function roundRect(x, y, width, height, radius) {
        ctx.beginPath();
        ctx.roundRect(x, y, width, height, radius);
      }

      function draw() {
        ctx.clearRect(0, 0, canvas.width, canvas.height);

        ctx.fillStyle = "#0c121a";
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        ctx.strokeStyle = "#182330";
        ctx.lineWidth = 1;
        for (let i = 0; i <= w; i++) {
          ctx.beginPath();
          ctx.moveTo(i * cell, 0);
          ctx.lineTo(i * cell, canvas.height);
          ctx.stroke();
        }
        for (let i = 0; i <= h; i++) {
          ctx.beginPath();
          ctx.moveTo(0, i * cell);
          ctx.lineTo(canvas.width, i * cell);
          ctx.stroke();
        }

        if (foodCell) {
          const [fx, fy] = foodCell;
          const cx = fx * cell + cell / 2;
          const cy = fy * cell + cell / 2;

          ctx.fillStyle = "rgba(255, 92, 124, 0.18)";
          ctx.beginPath();
          ctx.arc(cx, cy, cell * 0.40, 0, Math.PI * 2);
          ctx.fill();

          ctx.fillStyle = "#ff5c7c";
          ctx.beginPath();
          ctx.arc(cx, cy, cell * 0.25, 0, Math.PI * 2);
          ctx.fill();

          ctx.fillStyle = "#ffd5df";
          ctx.beginPath();
          ctx.arc(cx - cell * 0.08, cy - cell * 0.09, cell * 0.07, 0, Math.PI * 2);
          ctx.fill();
        }

        body.forEach((part, index) => {
          const x = part[0] * cell + 3;
          const y = part[1] * cell + 3;
          const size = cell - 6;

          ctx.fillStyle = index === 0 ? "#69f29b" : "#37bd70";
          roundRect(x, y, size, size, index === 0 ? 8 : 6);
          ctx.fill();

          if (index === 0) {
            ctx.fillStyle = "#102518";
            const [dx, dy] = vectors[direction];
            const eyeOffsetX = dx * 5;
            const eyeOffsetY = dy * 5;

            ctx.beginPath();
            ctx.arc(x + size * 0.34 + eyeOffsetX, y + size * 0.34 + eyeOffsetY, 2.5, 0, Math.PI * 2);
            ctx.arc(x + size * 0.66 + eyeOffsetX, y + size * 0.66 + eyeOffsetY, 2.5, 0, Math.PI * 2);
            ctx.fill();
          }
        });

        if (!isAlive) {
          ctx.fillStyle = "rgba(5, 9, 14, 0.70)";
          ctx.fillRect(0, 0, canvas.width, canvas.height);
          ctx.fillStyle = "#ffffff";
          ctx.textAlign = "center";
          ctx.font = "bold 36px system-ui, sans-serif";
          ctx.fillText("GAME OVER", canvas.width / 2, canvas.height / 2 - 8);
          ctx.fillStyle = "#b8cbe0";
          ctx.font = "20px system-ui, sans-serif";
          ctx.fillText("Press Start or Reset to play again", canvas.width / 2, canvas.height / 2 + 29);
        }
      }

      function reset() {
        stop();
        body = [
          [6, 10],
          [5, 10],
          [4, 10]
        ];
        direction = "right";
        queuedDirection = null;
        points = 0;
        isAlive = true;
        placeRandomFood();
        updateScore();
        draw();
      }

      function setDir(nextDirection) {
        if (!vectors[nextDirection] || !isAlive) return;
        if (nextDirection === opposite[direction]) return;
        if (queuedDirection === null) queuedDirection = nextDirection;
      }

      function setFood(x, y) {
        x = Number(x);
        y = Number(y);
        if (!Number.isInteger(x) || !Number.isInteger(y)) return;
        if (x < 0 || x >= w || y < 0 || y >= h) return;
        foodCell = [x, y];
        draw();
      }

      function tick() {
        if (!isAlive) return false;

        if (queuedDirection && queuedDirection !== opposite[direction]) {
          direction = queuedDirection;
        }
        queuedDirection = null;

        const [dx, dy] = vectors[direction];
        const head = body[0];
        const nextHead = [head[0] + dx, head[1] + dy];

        if (
          nextHead[0] < 0 ||
          nextHead[0] >= w ||
          nextHead[1] < 0 ||
          nextHead[1] >= h ||
          cellOccupied(nextHead[0], nextHead[1])
        ) {
          isAlive = false;
          stop();
          draw();
          return false;
        }

        const ate = foodCell && sameCell(nextHead, foodCell);
        body.unshift(nextHead);

        if (ate) {
          points++;
          placeRandomFood();
          updateScore();
        } else {
          body.pop();
        }

        draw();
        return true;
      }

      function start() {
        if (!isAlive) reset();
        if (timer === null) {
          timer = setInterval(tick, tickMs);
        }
      }

      function stop() {
        if (timer !== null) {
          clearInterval(timer);
          timer = null;
        }
      }

      window.game = {
        w,
        h,
        reset,
        tick,
        setDir,
        setFood,
        snake: () => body.map(part => [part[0], part[1]]),
        food: () => foodCell ? [foodCell[0], foodCell[1]] : null,
        alive: () => isAlive,
        score: () => points
      };

      document.addEventListener("keydown", event => {
        const keyDirections = {
          ArrowUp: "up",
          ArrowDown: "down",
          ArrowLeft: "left",
          ArrowRight: "right"
        };
        if (keyDirections[event.key]) {
          event.preventDefault();
          setDir(keyDirections[event.key]);
        }
      });

      startButton.addEventListener("click", start);
      pauseButton.addEventListener("click", stop);
      resetButton.addEventListener("click", reset);

      reset();
    })();
  </script>
</body>
</html>
